"use client"
import Link from "next/link";
import { useState } from "react";

export default function login() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    async function handleLogin(e) {
        e.preventDefault();
        const res = await fetch("http://localhost:8080/login", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({
                email: email,
                password: password,
            }),
        })
        if (res.ok) {
            alert("Login successful");
            router.push("/");
        } else {
            alert("Login failed");
        }

    }

    return (
        <div className="flex flex-col gap-4 justify-center items-center h-screen">
            <h1 className="text-2xl font-bold mb-4">Login</h1>
            <div className="flex flex-col gap-4 w-1/2">
                <form onSubmit={handleLogin} className="flex flex-col gap-4">
                    <label htmlFor="email">Email</label>
                    <input type="email" placeholder="Email" className="border border-gray-300 rounded-md px-4 py-2" value={email} onChange={(e) => setEmail(e.target.value)} />
                    <label htmlFor="password">Password</label>
                    <input type="password" placeholder="Password" className="border border-gray-300 rounded-md px-4 py-2" value={password} onChange={(e) => setPassword(e.target.value)} />
                    <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded-md">Login</button>
                    <Link href="/register" >Register</Link>
                </form>
            </div>
        </div>
    );
}